// Initialize the autonomous improvement loop
const input = $input.first().json.body || $input.first().json || {};

const config = {
  max_cycles: input.max_cycles || 5,
  current_cycle: 1,
  test_limit: input.test_limit || 100,
  batch_size: input.batch_size || 50,
  eval_webhook: '{{ $env.WEBHOOK_BASE_URL }}/webhook/parallel-eval-runner-v6',
  autofix_webhook: '{{ $env.WEBHOOK_BASE_URL }}/webhook/autorefinement-trigger',
  agent_id: input.agent_id || 'agent_8001kdgp7qbyf4wvhs540be78vew',
  started_at: new Date().toISOString(),
  trigger_source: input.trigger_source || 'scheduled',
  history: []
};

return [{ json: config }];

// Call the parallel evaluation runner
const config = $input.first().json;

try {
  const evalResponse = await this.helpers.httpRequest({
    method: 'POST',
    url: config.eval_webhook,
    body: {
      limit: config.test_limit,
      batch_size: config.batch_size
    },
    headers: { 'Content-Type': 'application/json' },
    json: true,
    timeout: 300000 // 5 min timeout for 1000 tests
  });

  // Record this cycle's result
  const cycleResult = {
    cycle: config.current_cycle,
    pass_rate: evalResponse.summary?.pass_rate || '0%',
    passed: evalResponse.summary?.passed || 0,
    failed: evalResponse.summary?.failed || 0,
    needs_fix: evalResponse.needs_autocorrection || false,
    timestamp: new Date().toISOString()
  };

  config.history.push(cycleResult);
  config.latest_result = evalResponse;
  config.needs_autocorrection = evalResponse.needs_autocorrection || false;
  config.current_pass_rate = evalResponse.summary?.pass_rate || '0%';

  return [{ json: config }];
} catch (error) {
  config.error = error.message;
  config.needs_autocorrection = false; // Don't autofix on eval error
  return [{ json: config }];
}

// Trigger the autorefinement workflow with failure data
const config = $input.first().json;
const evalResult = config.latest_result;

// Extract failures for autorefinement
const failures = [];
if (evalResult.failures_by_category) {
  for (const [category, categoryFailures] of Object.entries(evalResult.failures_by_category)) {
    failures.push(...categoryFailures.slice(0, 5)); // Max 5 per category
  }
}

try {
  const autofixResponse = await this.helpers.httpRequest({
    method: 'POST',
    url: config.autofix_webhook,
    body: {
      failures: failures,
      agent_id: config.agent_id,
      total_tests: evalResult.summary?.total_tests || 0,
      passed_tests: evalResult.summary?.passed || 0,
      cycle: config.current_cycle
    },
    headers: { 'Content-Type': 'application/json' },
    json: true,
    timeout: 120000 // 2 min for autofix
  });

  config.autofix_result = autofixResponse;
  config.autofix_success = autofixResponse.status === 'success';

} catch (error) {
  config.autofix_error = error.message;
  config.autofix_success = false;
}

// Increment cycle for next iteration
config.current_cycle += 1;

return [{ json: config }];

// Build final summary - 100% pass rate achieved
const config = $input.first().json;

const summary = {
  status: 'PERFECT',
  emoji: '🎉',
  message: `100% pass rate achieved in ${config.current_cycle} cycle(s)!`,
  agent_id: config.agent_id,
  final_pass_rate: config.current_pass_rate,
  total_cycles: config.current_cycle,
  started_at: config.started_at,
  completed_at: new Date().toISOString(),
  history: config.history,
  trigger_source: config.trigger_source
};

return [{ json: summary }];

// Build final summary - max cycles reached without 100%
const config = $input.first().json;

const summary = {
  status: 'MAX_CYCLES_REACHED',
  emoji: '⚠️',
  message: `Max ${config.max_cycles} cycles reached. Manual review needed.`,
  agent_id: config.agent_id,
  final_pass_rate: config.current_pass_rate,
  total_cycles: config.max_cycles,
  started_at: config.started_at,
  completed_at: new Date().toISOString(),
  history: config.history,
  remaining_failures: config.latest_result?.failure_count || 0,
  trigger_source: config.trigger_source
};

return [{ json: summary }];

